        vector<int> idx(n);
        iota(idx.begin(), idx.end(), 0);
        sort(idx.begin(), idx.end(), [&](int a, int b){ return score[a] > score[b]; });
        vector<string> ans(n);
        vector<string> m = {"Gold Medal","Silver Medal","Bronze Medal"};
